import { _decorator, Component, director, Node, Label, Button, ProgressBar, Sprite } from 'cc';
import { GameManager } from '../Core/GameManager';
import { Utils } from '../Utils/Utils';

const { ccclass, property } = _decorator;

@ccclass('BattleScene')
export class BattleScene extends Component {
    @property(Node)
    playerNode: Node = null;
    
    @property(Node)
    enemyNode: Node = null;
    
    @property(ProgressBar)
    playerHpBar: ProgressBar = null;
    
    @property(ProgressBar)
    enemyHpBar: ProgressBar = null;
    
    @property(Label)
    battleLog: Label = null;
    
    @property(Button)
    attackBtn: Button = null;
    
    @property(Button)
    skillBtn: Button = null;
    
    @property(Button)
    itemBtn: Button = null;
    
    @property(Button)
    fleeBtn: Button = null;
    
    private player = {
        hp: 100,
        maxHp: 100,
        mp: 50,
        maxMp: 50,
        attack: 20,
        defense: 10
    };
    
    private enemy = {
        name: '试炼傀儡',
        hp: 80,
        maxHp: 80,
        attack: 15,
        defense: 5
    };
    
    private isPlayerTurn: boolean = true;
    private battleLogText: string[] = [];
    
    onLoad() {
        this.attackBtn.node.on(Button.EventType.CLICK, this.onAttack, this);
        this.skillBtn.node.on(Button.EventType.CLICK, this.onSkill, this);
        this.itemBtn.node.on(Button.EventType.CLICK, this.onItem, this);
        this.fleeBtn.node.on(Button.EventType.CLICK, this.onFlee, this);
    }
    
    start() {
        this.updateUI();
        this.addLog('战斗开始！');
    }
    
    updateUI() {
        this.playerHpBar.progress = this.player.hp / this.player.maxHp;
        this.enemyHpBar.progress = this.enemy.hp / this.enemy.maxHp;
        
        // 更新按钮状态
        this.attackBtn.interactable = this.isPlayerTurn;
        this.skillBtn.interactable = this.isPlayerTurn && this.player.mp >= 10;
        this.itemBtn.interactable = this.isPlayerTurn;
        this.fleeBtn.interactable = this.isPlayerTurn;
    }
    
    onAttack() {
        if (!this.isPlayerTurn) return;
        
        // 玩家攻击
        const damage = Math.max(1, this.player.attack - this.enemy.defense + Utils.randomInt(-5, 5));
        this.enemy.hp = Math.max(0, this.enemy.hp - damage);
        this.addLog(`你对${this.enemy.name}造成${damage}点伤害！`);
        
        this.updateUI();
        
        if (this.enemy.hp <= 0) {
            this.onWin();
            return;
        }
        
        // 敌人回合
        this.isPlayerTurn = false;
        this.scheduleOnce(() => this.enemyTurn(), 1);
    }
    
    onSkill() {
        if (!this.isPlayerTurn || this.player.mp < 10) return;
        
        // 使用技能（简化版重击）
        this.player.mp -= 10;
        const damage = Math.max(1, Math.floor(this.player.attack * 1.5) - this.enemy.defense);
        this.enemy.hp = Math.max(0, this.enemy.hp - damage);
        this.addLog(`你使用重击，对${this.enemy.name}造成${damage}点伤害！`);
        
        this.updateUI();
        
        if (this.enemy.hp <= 0) {
            this.onWin();
            return;
        }
        
        this.isPlayerTurn = false;
        this.scheduleOnce(() => this.enemyTurn(), 1);
    }
    
    onItem() {
        if (!this.isPlayerTurn) return;
        this.addLog('背包功能开发中...');
    }
    
    onFlee() {
        if (!this.isPlayerTurn) return;
        
        if (Utils.probability(0.5)) {
            this.addLog('逃跑成功！');
            this.scheduleOnce(() => director.loadScene('MainScene'), 1);
        } else {
            this.addLog('逃跑失败！');
            this.isPlayerTurn = false;
            this.scheduleOnce(() => this.enemyTurn(), 1);
        }
    }
    
    enemyTurn() {
        if (this.enemy.hp <= 0) return;
        
        const damage = Math.max(1, this.enemy.attack - this.player.defense + Utils.randomInt(-3, 3));
        this.player.hp = Math.max(0, this.player.hp - damage);
        this.addLog(`${this.enemy.name}对你造成${damage}点伤害！`);
        
        this.updateUI();
        
        if (this.player.hp <= 0) {
            this.onLose();
            return;
        }
        
        // 恢复法力
        this.player.mp = Math.min(this.player.maxMp, this.player.mp + 5);
        
        this.isPlayerTurn = true;
        this.updateUI();
    }
    
    onWin() {
        this.addLog('战斗胜利！');
        
        // 奖励
        const rewardMoney = Utils.randomInt(100, 200);
        GameManager.getInstance().playerData.addCurrency('incense_money', rewardMoney);
        this.addLog(`获得${rewardMoney}香火钱！`);
        
        this.scheduleOnce(() => director.loadScene('MainScene'), 2);
    }
    
    onLose() {
        this.addLog('战斗失败...');
        this.scheduleOnce(() => director.loadScene('MainScene'), 2);
    }
    
    addLog(text: string) {
        this.battleLogText.push(text);
        if (this.battleLogText.length > 5) {
            this.battleLogText.shift();
        }
        this.battleLog.string = this.battleLogText.join('\n');
    }
}
